package com.kunal.replaybench.service; import com.kunal.replaybench.model.Scenario; import org.springframework.stereotype.Component; @Component public class RuleAgent implements AgentStrategy{ public String type(){return "RULE";} public String decide(Scenario s){ String x=s.signal.toLowerCase(); if(x.contains("kafka")) return "scale_consumers"; if(x.contains("latency")) return "enable_rate_limit"; if(x.contains("deploy")) return "rollback_deployment"; return "restart_service"; }}
